 10→// CacheKey identifies a cached capability set by user identity and server name.
 11→type CacheKey struct {
 12→	Subject    string // OAuth sub claim (user identity)
 13→	ServerName string // MCP server name
 14→}
 15→
 16→// CacheEntry holds the cached MCP capabilities for a user+server pair.
 17→// Entries are immutable once stored; Set replaces the entire entry.
 18→type CacheEntry struct {
 19→	Tools     []mcp.Tool
 20→	Resources []mcp.Resource
 21→	Prompts   []mcp.Prompt
 22→	StoredAt  time.Time
 23→	ExpiresAt time.Time
 24→	// graceDeadline is the point after which the entry is eligible for eviction.
 25→	// Set to StoredAt + 2*TTL.
 26→	graceDeadline time.Time
 27→}
 28→
 29→// IsExpired returns true if the entry has passed its TTL.
 30→func (e *CacheEntry) IsExpired() bool {
 31→	return time.Now().After(e.ExpiresAt)
 32→}
 33→
 34→// IsStale returns true if the entry is expired but still within the grace period
 35→// (usable for stale-while-revalidate). Returns false if the entry is fresh or
 36→// has passed the grace period.
 37→func (e *CacheEntry) IsStale() bool {
 38→	now := time.Now()
 39→	return now.After(e.ExpiresAt) && !now.After(e.graceDeadline)
 40→}
 41→
 42→// CapabilityCache stores per-user, per-server MCP capabilities independently
 43→// of connection state. It supports TTL-based expiry with stale-while-revalidate
 44→// semantics: expired entries are still returned by Get so callers can serve
 45→// stale data while triggering a background refresh.
 46→//
 47→// A background goroutine periodically evicts entries that have passed the grace
 48→// period (2x TTL). Callers must call Stop() to prevent goroutine leaks.
 49→type CapabilityCache struct {
 50→	mu         sync.RWMutex
 51→	entries    map[CacheKey]*CacheEntry
 52→	defaultTTL time.Duration
 53→	stopCh     chan struct{}
 54→	stopped    chan struct{}
 55→	stopOnce   sync.Once
 56→}
 57→
 58→// NewCapabilityCache creates a cache with the given default TTL and starts a
 59→// background cleanup goroutine that runs every defaultTTL/2. Callers must call
 60→// Stop() when the cache is no longer needed.
 61→func NewCapabilityCache(defaultTTL time.Duration) *CapabilityCache {
 62→	c := &CapabilityCache{
 63→		entries:    make(map[CacheKey]*CacheEntry),
 64→		defaultTTL: defaultTTL,
 65→		stopCh:     make(chan struct{}),
 66→		stopped:    make(chan struct{}),
 67→	}
 68→
 69→	cleanupInterval := defaultTTL / 2
 70→	if cleanupInterval <= 0 {
 71→		cleanupInterval = time.Second
 72→	}
 73→
 74→	go c.cleanupLoop(cleanupInterval)
 75→
 76→	return c
 77→}
 78→
 79→// Get returns the cached capabilities for a user+server pair. It returns the
 80→// entry and true if found (even if expired, supporting stale-while-revalidate).
 81→// The caller should check entry.IsExpired() to decide whether to trigger a
 82→// background refresh. Returns nil and false only if no entry exists.
 83→func (c *CapabilityCache) Get(subject, serverName string) (*CacheEntry, bool) {
 84→	c.mu.RLock()
 85→	defer c.mu.RUnlock()
 86→
 87→	entry, ok := c.entries[CacheKey{Subject: subject, ServerName: serverName}]
 88→	return entry, ok
 89→}
 90→
 91→// Set stores capabilities for a user+server pair with the default TTL.
 92→func (c *CapabilityCache) Set(subject, serverName string, tools []mcp.Tool, resources []mcp.Resource, prompts []mcp.Prompt) {
 93→	c.SetWithTTL(subject, serverName, tools, resources, prompts, c.defaultTTL)
 94→}
 95→
 96→// SetWithTTL stores capabilities for a user+server pair with a custom TTL.
 97→func (c *CapabilityCache) SetWithTTL(subject, serverName string, tools []mcp.Tool, resources []mcp.Resource, prompts []mcp.Prompt, ttl time.Duration) {
 98→	now := time.Now()
 99→	entry := &CacheEntry{
100→		Tools:         append([]mcp.Tool(nil), tools...),
101→		Resources:     append([]mcp.Resource(nil), resources...),
102→		Prompts:       append([]mcp.Prompt(nil), prompts...),
103→		StoredAt:      now,
104→		ExpiresAt:     now.Add(ttl),
105→		graceDeadline: now.Add(2 * ttl),
106→	}
107→
108→	c.mu.Lock()
109→	c.entries[CacheKey{Subject: subject, ServerName: serverName}] = entry
110→	c.mu.Unlock()
111→}
112→
113→// InvalidateUser removes all cached entries for a user (e.g., on logout).
114→func (c *CapabilityCache) InvalidateUser(subject string) {
115→	c.mu.Lock()
116→	defer c.mu.Unlock()
117→
118→	for key := range c.entries {
119→		if key.Subject == subject {
120→			delete(c.entries, key)
121→		}
122→	}
123→}
124→
125→// InvalidateServer removes all cached entries for a server (e.g., on deregistration).
126→func (c *CapabilityCache) InvalidateServer(serverName string) {
127→	c.mu.Lock()
128→	defer c.mu.Unlock()
129→
130→	for key := range c.entries {
131→		if key.ServerName == serverName {
132→			delete(c.entries, key)
133→		}
134→	}
135→}
136→
137→// Invalidate removes the cached entry for a specific user+server pair.
138→func (c *CapabilityCache) Invalidate(subject, serverName string) {
139→	c.mu.Lock()
140→	delete(c.entries, CacheKey{Subject: subject, ServerName: serverName})
141→	c.mu.Unlock()
142→}
