153→// cleanupLoop periodically evicts entries that have passed their grace deadline.
154→func (c *CapabilityCache) cleanupLoop(interval time.Duration) {
155→	defer close(c.stopped)
156→
157→	ticker := time.NewTicker(interval)
158→	defer ticker.Stop()
